const body = $json.body ?? $json;
const envelopeId = body.envelopeId ?? body.data?.envelopeId ?? '';
const resourceType = body.resourceType ?? body.data?.resourceType ?? 'contract';
const status = String(body.status ?? body.event ?? body.data?.status ?? '').toLowerCase();
const correlationId = body.correlationId ?? '';

if (!envelopeId) {
  throw new Error('envelopeId is required');
}

const signedStatuses = ['completed', 'signed', 'envelope-completed'];
const signed = signedStatuses.includes(status);

return [{
  json: {
    success: true,
    provider: 'docusign',
    envelopeId,
    resourceType,
    signed,
    status,
    correlationId,
    message: signed
      ? 'Firma electrónica confirmada.'
      : 'Evento de firma recibido.'
  }
}];
